        },
        "text": "Changes to Accounting Methods Required Under the Tax Reform Act of 1986"
    },
    {
        "type": "NarrativeText",
        "element_id": "",
        "metadata": {
            "coordinates": {
                "points": [
                    [
                        28.0,
                        1365.0
