                    ],
                    [
                        959.0,
                        981.0
                    ]
                ],
                "system": "PixelSpace",
                "layout_width": 1512,
                "layout_height": 2050
            },
            "filename": "IRS-form-1987.pdf",
            "file_directory": "../ingest-fixtures-files-all",
            "last_modified": "2023-10-04T22:05:33",
            "filetype": "application/pdf",
            "parent_id": "5756fb398995bb6518a87637f24f426e",
            "languages": [
                "eng"
            ],
            "page_number": 1
        },
        "text": "Generally, applicants must file this form within the first 180 days of the tax year in which it is desired to make the change."
    },
    {
        "type": "UncategorizedText",
        "element_id": "",
        "metadata": {
            "coordinates": {
                "points": [
                    [
                        525.0,
                        1056.0
                    ],
