                "system": "PixelSpace",
                "layout_width": 1512,
                "layout_height": 2067
            },
            "filename": "IRS-form-1987.pdf",
            "file_directory": "../ingest-fixtures-files-all",
            "last_modified": "2023-10-04T22:05:33",
            "filetype": "application/pdf",
            "parent_id": "8d6743276d5bc8e32d0b05ba0b232db8",
            "languages": [
                "eng"
            ],
            "page_number": 2
        },
        "text": "All long-term contracts entered into after February 28, 1986, except for real property construction contracts expected to be completed within 2 years by contractors whose average annual gross receipts for the 3 prior tax years do not exceed $10,000,000, must be accounted for using either the percentage of completion-capitalized cost method or the percentage of completion method. See section 460."
    },
    {
        "type": "NarrativeText",
        "element_id": "",
        "metadata": {
